module top_module(
    input A1,
    input A2,
    input B1,
    output Y
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire neg_output_logic = (A1 || (A2 && !A1) || (!A1 && !A2 && B1));
    assign Y = neg_output_logic ? 1'b1 : 1'b0;

endmodule
